    "source": "\\documentclass[crop, tikz]{standalone}\n\\usepackage{tikz}\n\\usepackage{pgfplots}\n\n\\definecolor{olivegreen}{rgb}{0,0.6,0}\n\n\\begin{document}\n\\begin{tikzpicture}[samples=1000, domain=0:10]\n\n\t\\begin{axis}[\n\t\twidth=11cm, height=3.5cm,\n\t\txtick=\\empty,\n\t\tytick=\\empty,\n\t\txlabel={\\large $t$},\n\t\tylabel={\\large $x(t)$},\n\t\txmin=0, xmax=11,\n\t\tymin=-3, ymax=5,\n\t\taxis lines = middle,\n\t\tvery thick,\n\t\ttrig format = rad\n\t]\n\t\t\\addplot [no markers, smooth, thick] {2*sin(2*pi*0.25*x)};\n\t\\end{axis}\n\t\t\n\t\\begin{axis}[\n\t\tat={(0, -2.25cm)},\n\t\twidth=11cm, height=3.5cm,\n\t\txtick=\\empty,\n\t\tytick=\\empty,\n\t\txlabel={\\large $t$},\n\t\tylabel={\\textcolor{blue}{carrier wave}},\n\t\txmin=0, xmax=11,\n\t\tymin=-3, ymax=5,\n\t\taxis lines = middle,\n\t\tvery thick,\n\t\ttrig format = rad\n\t]\n\t\t\\addplot [no markers, smooth, blue, very thick] {2*sin(6*pi*x)};\n\t\\end{axis}\n\t\t\n\t\\begin{axis}[\n\t\tat={(0, -4.5cm)},\n\t\twidth=11cm, height=3.5cm,\n\t\txtick=\\empty,\n\t\tytick=\\empty,\n\t\txlabel={\\large $t$},\n\t\tylabel={\\textcolor{olivegreen}{FM wave}},\n\t\txmin=0, xmax=11,\n\t\tymin=-3, ymax=5,\n\t\taxis lines = middle,\n\t\tvery thick,\n\t\ttrig format = rad\n\t]\n\t\t\\addplot expression [no markers, smooth, olivegreen, very thick] {2*sin(2*pi*3*x - 8*cos(2*pi*0.25*x))};\n\t\\end{axis}\n\t\n\\end{tikzpicture}\n\\end{document}\n"
