    "path": "Hamiltonian graph/hamiltonian_graph.tex",
    "sourceUrl": "https://github.com/PetarV-/TikZ/blob/master/Hamiltonian graph/hamiltonian_graph.tex",
    "source": "\\documentclass[crop, tikz]{standalone}\n\\usepackage{tikz}\n\\usepackage{tkz-graph}\n\n\\begin{document}\n\\begin{tikzpicture}[scale=0.8,every node/.style={scale=0.7},font=\\tt]\n\t\\SetUpEdge[lw         = 1.5pt,\n\t\t\t\tcolor      = red,\n\t\t\t\tlabelcolor = white]\n\t\\GraphInit[vstyle=Normal] \n\t\\SetGraphUnit{3}\n\t\\tikzset{VertexStyle/.append  style={fill}}\n\t\\Vertex{ATG}\n\t\\EA(ATG){TGG}\n\t\\EA(TGG){GGC}\n\t\\SO(GGC){GCG}\n\t\\WE(GCG){CGT}\n\t\\WE(CGT){GTG}\n\t\\WE(GTG){TGC}\n\t\\WE(TGC){GCA}\n\t\\NO(GCA){CAA}\n\t\\EA(CAA){AAT}\n\t\\tikzset{EdgeStyle/.style={-stealth, color=black}}\n\t\\Edge(ATG)(TGC)\n\t\\Edge(GTG)(TGG)\n\t\\Edge(GGC)(GCA)\n\t\\tikzset{EdgeStyle/.style={-stealth, color=black, bend right}}\n\t\\Edge(TGC)(GCG)\n\t\\tikzset{EdgeStyle/.style={-stealth}}\n\t\\Edge(ATG)(TGG)\n\t\\Edge(TGG)(GGC)\n\t\\Edge(GGC)(GCG)\n\t\\Edge(GCG)(CGT)\n\t\\Edge(CGT)(GTG)\n\t\\Edge(GTG)(TGC)\n\t\\Edge(TGC)(GCA)\n\t\\Edge(GCA)(CAA)\n\t\\Edge(CAA)(AAT)\n\t\\Edge(AAT)(ATG)\n\\end{tikzpicture}\n\\end{document}\n"
